/// <reference lib="webworker" />
declare const self: ServiceWorkerGlobalScope & { __WB_MANIFEST: any[] };

import { precacheAndRoute } from 'workbox-precaching';

// Precache all assets generated by Vite build
precacheAndRoute(self.__WB_MANIFEST);

// Push notification event handler
self.addEventListener('push', (event: any) => {
    let data: any = {};
    try {
        data = event.data?.json() ?? {};
    } catch (e) {
        console.error('Error parsing push data', e);
    }
    const title = data.title || 'JamesTronic Notification';
    const parsedUrl = data.url || '/';
    
    const options = {
        body: data.body || 'You have a new notification.',
        icon: '/pwa-192x192.png',
        badge: '/pwa-192x192.png',
        vibrate: [200, 100, 200, 100, 200, 100, 400],
        tag: 'notification-' + (data.request_id || data.ticket_id || Date.now()),
        renotify: true,
        requireInteraction: true,
        data: {
            url: parsedUrl,
            request_id: data.request_id,
            ticket_id: data.ticket_id
        },
        actions: [
            { action: 'view', title: 'Open' },
            { action: 'dismiss', title: 'Dismiss' }
        ]
    };

    // Increment App Badge
    if ('setAppBadge' in navigator) {
        event.waitUntil(
            // We don't have direct access to the current badge count synchronously in SW,
            // but we can try to guess it or just set it to a generic dot (null) if count unknown.
            // For now, we will set it to 1, and the React app will sync the true count when opened.
            (navigator as any).setAppBadge(1).catch(console.error)
        );
    }

    event.waitUntil(
        self.registration.showNotification(title, options)
    );
});

// Notification click handler
self.addEventListener('notificationclick', (event: any) => {
    event.notification.close();

    // Clear App Badge when interacted with
    if ('clearAppBadge' in navigator) {
        event.waitUntil((navigator as any).clearAppBadge().catch(console.error));
    }

    if (event.action === 'dismiss') return;

    const urlToOpen = event.notification.data?.url || '/';

    event.waitUntil(
        (self as any).clients.matchAll({ type: 'window', includeUncontrolled: true }).then((windowClients: any[]) => {
            // Try to focus an existing window matching the base route (e.g. /dealer, /transport)
            const targetBase = urlToOpen.split('?')[0];
            for (const client of windowClients) {
                if (client.url.includes(targetBase) && 'focus' in client) {
                    client.navigate(urlToOpen);
                    return client.focus();
                }
            }
            // Open a new window if none exists
            return (self as any).clients.openWindow(urlToOpen);
        })
    );
});
